html, body {
  overflow: hidden !important;
  margin: 0;
  padding: 0;
}

.app {
  width: 100%;
  font-family: system-ui;
  background: #1E293B;
  border-radius: 6px;
  display: flex;
  flex-direction: column;
  box-sizing: border-box;
}

.header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 10px;
  color: white;
  border-bottom: 2px solid #64748b;
  font-weight: 600;
  width: 100%;
  box-sizing: border-box;
}

.sortIcon {
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  flex-shrink: 0;
}

.list {
  width: 100%;
  overflow: visible; /* remove internal scroll */
}

.row {
  padding: 7px 10px;
  cursor: pointer;
  color: white;
  font-size: 14px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.row:nth-child(odd) {
  background: #243447;
}

.row:nth-child(even) {
  background: #1E293B;
}

.row:hover {
  background: #334155;
}

.selected {
  background: #86efac !important;
  color: black;
}

